import React, { useRef, useState } from 'react';
import { motion, AnimatePresence, useReducedMotion, Variants } from 'framer-motion'; 
import { useNavigate } from 'react-router-dom';
import Reveal from '../components/Reveal';
import GlowButton from '../components/GlowButton';
import VibeCard from '../components/VibeCard';
import LabeledSlider from '../components/LabeledSlider';
import PageLayout from '../components/PageLayout';
import { SpecialText } from '../components/ui/special-text';
import { getMotionPresets } from '../ui/motion';

const personas = [
    { label: 'Family Route', img: '/img/cltfan2.jpg', desc: 'Parks & Museums' },
    { label: 'The Soloist', img: '/img/uptown1.jpg', desc: 'Work & Exploration' }, 
    { label: 'Squad Trip', img: '/img/cltfans.jpg', desc: 'Friends & Vacation' },
    { label: 'Date Night', img: '/img/optimist1.jpg', desc: 'Couples & Vibes' },
];

const vibes = [
    { id: 'sports', label: 'The Competitor', img: '/img/nascar.jpg', tags: 'Racing, Panthers, Energy' },
    { id: 'food', label: 'The Foodie', img: '/img/beergarden.jpg', tags: 'Breweries, Local Eats, Patios' },
    { id: 'music', label: 'The Socialite', img: '/img/cltconcert.avif', tags: 'Live Music, Rooftops, Nightlife' },
];

type SectionHeaderProps = {
    eyebrow: string;
    title: string;
    centered?: boolean;
};

const SectionHeader: React.FC<SectionHeaderProps> = ({ eyebrow, title, centered = false }) => (
    <div className={centered ? 'mx-auto max-w-3xl text-center' : ''}>
        <p className="section-eyebrow">{eyebrow}</p>
        <h2 className="section-title text-[#F9F8F3]">{title}</h2>
    </div>
);

type TestimonialCardProps = {
    quote: string;
    author: string;
};

const TestimonialCard: React.FC<TestimonialCardProps> = ({ quote, author }) => (
    <div className="glass-card rounded-[2rem] p-8">
        <p className="section-copy text-white/84">“{quote}”</p>
        <p className="mt-8 text-[11px] font-black uppercase tracking-[0.26em] text-gold/85">{author}</p>
    </div>
);

type FeatureStepCardProps = {
    step: string;
    title: string;
    body: string;
};

const FeatureStepCard: React.FC<FeatureStepCardProps> = ({ step, title, body }) => (
    <div className="glass-card rounded-[2rem] p-8">
        <p className="text-sm font-black uppercase tracking-[0.24em] text-emerald/90">{step}</p>
        <h3 className="mt-4 text-3xl font-serif italic text-white">{title}</h3>
        <p className="section-copy mt-4 text-white/74">{body}</p>
    </div>
);

type FaqCardProps = {
    question: string;
    answer: string;
};

const FaqCard: React.FC<FaqCardProps> = ({ question, answer }) => (
    <div className="glass-card rounded-[2rem] p-8">
        <h3 className="text-2xl font-serif italic text-white">{question}</h3>
        <p className="section-copy mt-4 text-white/74">{answer}</p>
    </div>
);

type VisualStoryCardProps = {
    title: string;
    description: string;
    image: string;
};

const VisualStoryCard: React.FC<VisualStoryCardProps> = ({ title, description, image }) => (
    <div className="glass-card overflow-hidden rounded-[2rem]">
        <div className="relative h-52 w-full overflow-hidden">
            <img src={image} alt={title} className="h-full w-full object-cover" loading="lazy" decoding="async" />
            <div className="absolute inset-0 bg-gradient-to-t from-[#080808]/70 via-[#080808]/15 to-transparent" />
        </div>
        <div className="p-7">
            <h3 className="text-2xl font-serif italic text-white">{title}</h3>
            <p className="section-copy mt-3 text-white/74">{description}</p>
        </div>
    </div>
);

const Home: React.FC = () => {
    const navigate = useNavigate();
    const reduceMotion = useReducedMotion() ?? false;
    const motionPresets = React.useMemo(() => getMotionPresets(reduceMotion), [reduceMotion]);
    const storySectionRef = useRef<HTMLDivElement>(null);
    const [step, setStep] = useState(0);
    const [hasAutoAdvanced, setHasAutoAdvanced] = useState(false);
    const [selections, setSelections] = useState({
        persona: '',
        hours: 24, 
        vibes: [] as string[],
        budget: 500,
        radius: 10
    });

    const formatTime = (h: number) => {
        if (h === 168) return "1 Week";
        if (h >= 24) {
            const days = Math.round(h / 24);
            return `${days} ${days === 1 ? 'Day' : 'Days'}`;
        }
        return `${h} Hrs`;
    };

    const handleStayDurationChange = (rawValue: number) => {
        const snappedValue = rawValue <= 24 ? rawValue : Math.round(rawValue / 24) * 24;
        updateSelection('hours', Math.max(1, Math.min(168, snappedValue)));
    };

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat('en-US', {
            style: 'currency', currency: 'USD', maximumFractionDigits: 0,
        }).format(amount);
    };

    const updateSelection = (field: string, value: any) => {
        setSelections(prev => ({ ...prev, [field]: value }));
    };

    const toggleVibe = (id: string) => {
        setSelections(prev => ({
            ...prev,
            vibes: prev.vibes.includes(id) ? prev.vibes.filter(v => v !== id) : [...prev.vibes, id]
        }));
    };

    const titleContainer: Variants = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: reduceMotion ? 0 : 0.045, delayChildren: reduceMotion ? 0 : 0.1 }
        }
    };

    const titleLetter: Variants = {
        hidden: reduceMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: 24 },
        show: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.22, 1, 0.36, 1] } }
    };

    const personaGrid: Variants = {
        hidden: motionPresets.staggerChildren.hidden,
        show: {
            opacity: 1,
            transition: { staggerChildren: reduceMotion ? 0 : 0.1, delayChildren: reduceMotion ? 0 : 0.08 },
        },
    };

    React.useEffect(() => {
        if (step !== 0 || hasAutoAdvanced) return;

        const onWheel = (event: WheelEvent) => {
            if (event.deltaY > 12 && window.scrollY < 40) {
                setHasAutoAdvanced(true);
                storySectionRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
        };

        window.addEventListener('wheel', onWheel, { passive: true });
        return () => window.removeEventListener('wheel', onWheel);
    }, [step, hasAutoAdvanced]);

    const openPlanner = () => {
        window.scrollTo({ top: 0, behavior: 'auto' });
        setStep(1);
    };

    React.useEffect(() => {
        if (step <= 0) {
            return;
        }

        const previousOverflow = document.body.style.overflow;
        document.body.style.overflow = 'hidden';

        return () => {
            document.body.style.overflow = previousOverflow;
        };
    }, [step]);

    React.useEffect(() => {
        const plannerActive = step > 0;
        document.body.dataset.plannerActive = plannerActive ? 'true' : 'false';
        window.dispatchEvent(new CustomEvent('planner-active-change', { detail: plannerActive }));
    }, [step]);

    React.useEffect(() => {
        return () => {
            document.body.dataset.plannerActive = 'false';
            window.dispatchEvent(new CustomEvent('planner-active-change', { detail: false }));
        };
    }, []);

    const plannerSteps = [1, 2, 3, 4, 5];
    const currentPlannerStep = Math.min(Math.max(step, 1), 5);

    const renderPlannerStep = () => {
        switch (step) {
            case 1:
                return (
                    <div className="relative mx-auto w-full max-w-6xl pt-3">
                        <div className="pointer-events-none absolute -inset-x-4 -inset-y-6 opacity-30">
                            <div className="grid-bg absolute inset-0 rounded-[2rem]" />
                            <div className="absolute inset-0 rounded-[2rem] bg-[linear-gradient(to_bottom,rgba(255,255,255,0.05)_1px,transparent_1px)] bg-[size:100%_4px] opacity-20" />
                        </div>

                        <h3 className="relative mb-14 text-center font-serif text-4xl italic md:text-5xl">Who are we planning for?</h3>

                        <motion.div
                            variants={personaGrid}
                            initial="hidden"
                            animate="show"
                            className="relative mx-auto grid max-w-6xl grid-cols-1 gap-10 px-0 md:grid-cols-2 xl:[grid-template-columns:repeat(4,minmax(220px,1fr))]"
                        >
                            {personas.map((p) => (
                                <VibeCard
                                    key={p.label}
                                    title={p.label}
                                    subtitle={p.desc}
                                    imageSrc={p.img}
                                    onClick={() => {
                                        updateSelection('persona', p.label);
                                        setStep(2);
                                    }}
                                />
                            ))}
                        </motion.div>
                    </div>
                );
            case 2:
                return (
                    <div className="mx-auto flex min-h-[68vh] w-full max-w-2xl flex-col items-center justify-center text-center">
                        <h3 className="mb-5 text-5xl font-serif italic">How long is the stay?</h3>
                        <div className="relative mb-7 inline-flex items-center justify-center px-8 py-4">
                            <div className="pointer-events-none absolute inset-0 rounded-full bg-radial from-[#B3A369]/22 via-[#B3A369]/10 to-transparent blur-2xl" />
                            <h4 className="relative text-[5.6rem] font-serif tracking-tighter text-[#B3A369] serif-glow md:text-[6.6rem]">
                                {formatTime(Number(selections.hours))}
                            </h4>
                        </div>
                        <input type="range" min="1" max="168" value={selections.hours} onChange={(e) => handleStayDurationChange(Number(e.target.value))} className="mb-8 w-full cursor-pointer appearance-none rounded-full bg-white/10 h-1 accent-uncc-green" />
                        <div className="flex justify-between px-2 text-[11px] font-black uppercase tracking-widest text-[#B3A369] opacity-60 w-full">
                            <span>1 Hour</span><span>1 Week</span>
                        </div>
                        <button onClick={() => setStep(3)} className="glow mt-20 rounded-full border border-emerald/45 bg-emerald px-16 py-5 text-sm font-black uppercase tracking-[0.22em] text-white shadow-[0_0_0_1px_rgba(148,163,184,0.16),0_0_24px_rgba(16,185,129,0.2),0_20px_44px_rgba(2,8,23,0.45)]">Confirm Time</button>
                    </div>
                );
            case 3:
                return (
                    <div className="mx-auto w-full max-w-6xl text-center pt-0">
                        <h3 className="text-5xl font-serif mb-12 italic">What's the mission?</h3>
                        <div className="mx-auto grid max-w-6xl grid-cols-1 gap-10 px-0 md:grid-cols-2 lg:[grid-template-columns:repeat(3,minmax(260px,1fr))] justify-items-center">
                            {vibes.map((v) => (
                                <VibeCard
                                    key={v.id}
                                    title={v.label}
                                    subtitle={v.tags}
                                    imageSrc={v.img}
                                    selected={selections.vibes.includes(v.id)}
                                    onClick={() => toggleVibe(v.id)}
                                />
                            ))}
                        </div>
                        {selections.vibes.length > 0 && <button onClick={() => setStep(4)} className="glow relative z-10 mt-10 rounded-full border border-emerald/45 bg-emerald px-14 py-4 text-xs font-black uppercase tracking-widest text-white">Next Step</button>}
                    </div>
                );
            case 4:
                return (
                    <div className="relative w-full px-2 sm:px-4">
                        <div className="pointer-events-none absolute inset-0 -z-10">
                            <div className="absolute left-1/2 top-1/2 h-[540px] w-[88%] -translate-x-1/2 -translate-y-1/2 rounded-full bg-radial from-emerald/18 via-gold/10 to-transparent blur-3xl" />
                            <div className="absolute inset-0 rounded-[2.2rem] bg-[linear-gradient(to_right,rgba(148,163,184,0.09)_1px,transparent_1px),linear-gradient(to_bottom,rgba(148,163,184,0.07)_1px,transparent_1px)] bg-[size:42px_42px] opacity-35" />
                        </div>

                        <motion.div
                            key="logistics"
                            initial={reduceMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: 26 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: reduceMotion ? 0.15 : 0.5, ease: 'easeOut' }}
                            className="mx-auto w-full max-w-2xl rounded-[28px] border border-white/15 bg-gradient-to-br from-[#0e1a2f]/95 via-[#0b1424]/92 to-[#0a1220]/95 px-9 py-12 shadow-[0_22px_55px_rgba(2,8,23,0.52),0_0_0_1px_rgba(148,163,184,0.14)] backdrop-blur-xl sm:w-[clamp(360px,46vw,672px)] sm:px-11 sm:py-14"
                        >
                            <h3 className="mb-12 text-center font-serif text-[3.1rem] italic leading-[0.96] text-gold md:text-[3.8rem]">Fine Tuning</h3>

                            <div className="space-y-16">
                                <LabeledSlider
                                    label="Radius"
                                    min={1}
                                    max={50}
                                    value={Number(selections.radius)}
                                    onChange={(value) => updateSelection('radius', value)}
                                    formatValue={(value) => `${value} mi`}
                                />

                                <LabeledSlider
                                    label="Budget"
                                    min={10}
                                    max={5000}
                                    step={10}
                                    value={Number(selections.budget)}
                                    onChange={(value) => updateSelection('budget', value)}
                                    formatValue={(value) => formatCurrency(value)}
                                />

                                {Number(selections.budget) >= 3000 && (
                                    <motion.div
                                        initial={reduceMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: 8 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        className="text-center text-[10px] font-black uppercase tracking-[0.3em] text-gold"
                                    >
                                        ✨ Platinum Experience Tier ✨
                                    </motion.div>
                                )}
                            </div>

                            <motion.button
                                onClick={() => setStep(5)}
                                whileHover={reduceMotion ? {} : { scale: 1.02 }}
                                whileTap={reduceMotion ? {} : { scale: 0.985 }}
                                transition={{ duration: 0.2, ease: 'easeOut' }}
                                className="group relative mt-14 min-w-[320px] w-full overflow-hidden rounded-full border border-gold/60 bg-gradient-to-r from-emerald/95 via-emerald to-emerald px-10 py-5 text-sm font-black uppercase tracking-[0.24em] text-white shadow-[0_0_0_1px_rgba(148,163,184,0.14),0_0_28px_rgba(16,185,129,0.26),0_18px_42px_rgba(2,8,23,0.5)] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/80"
                            >
                                <span className="pointer-events-none absolute inset-0 -translate-x-full bg-gradient-to-r from-transparent via-white/30 to-transparent transition-transform duration-700 group-hover:translate-x-full" />
                                <span className="relative z-10">Generate Experience</span>
                            </motion.button>
                        </motion.div>
                    </div>
                );
            case 5:
                return (
                    <div className="mx-auto flex min-h-[68vh] w-full items-center justify-center px-4">
                        <div className="glass mx-auto flex w-full max-w-4xl flex-col items-center rounded-[5rem] p-20 text-center shadow-2xl">
                            <h3 className="mb-8 text-[5.6rem] font-serif italic leading-tight text-uncc-gold md:text-[6.4rem]">Ready to Roll.</h3>
                            <div className="mx-auto max-w-2xl">
                                <p className="mb-16 text-xl leading-relaxed text-white/80 font-inter">
                                    Your custom Queen City pulse is synchronized! We've mapped out the perfect {formatTime(Number(selections.hours))} journey for your {selections.persona}.
                                </p>
                            </div>
                            <button
                                onClick={() => navigate('/itinerary', { state: { selections } })}
                                className="glow mx-auto rounded-full border border-emerald/45 bg-emerald px-14 py-6 text-sm font-black uppercase tracking-[0.4em] text-white transition-all hover:scale-105"
                            >
                                Unlock Your Dashboard
                            </button>
                        </div>
                    </div>
                );
            default:
                return null;
        }
    };

    return (
        <div className="relative min-h-screen w-full overflow-hidden bg-[#080808] text-white font-inter">
            {/* DYNAMIC BACKGROUND */}
            <div className="fixed inset-0 -z-10">
                <img 
                    src={step === 5 ? "/img/cltconcert.avif" : "/img/cltskyline1.jpg"} 
                    className={`w-full h-full object-cover transition-all duration-[1200ms] ${step > 0 ? 'scale-105 brightness-[0.2] blur-sm' : 'brightness-50'}`} 
                    alt="Charlotte Backdrop" 
                />
                <div className="absolute inset-0 bg-gradient-to-b from-black/20 via-[#080808]/80 to-[#080808]" />
            </div>

            <PageLayout
                className={`min-h-screen ${step > 0 ? 'overflow-hidden' : ''}`}
                contentClassName={step > 0 ? 'max-w-none min-h-[calc(100vh-2in)] space-y-0' : ''}
            >
                {step === 0 ? (
                    <div className="flex min-h-screen items-center justify-center">
                        <Reveal>
                            <motion.div
                                key="hero"
                                initial={motionPresets.pageTransition.initial}
                                animate={motionPresets.pageTransition.animate}
                                exit={motionPresets.pageTransition.exit}
                                transition={motionPresets.pageTransition.transition}
                                className="relative text-center"
                            >
                                <motion.h1
                                    variants={titleContainer}
                                    initial="hidden"
                                    animate="show"
                                    className="mb-7 select-none font-inter text-[16vw] font-black leading-[0.88] tracking-[-0.04em] sm:text-[7.4rem] md:text-[9rem]"
                                >
                                    <span className="inline-flex">
                                        {Array.from('CLT').map((char, index) => (
                                            <motion.span key={`clt-${index}`} variants={titleLetter} className="text-[#00703C]">
                                                {char}
                                            </motion.span>
                                        ))}
                                    </span>
                                    <span className="inline-flex hero-title-shimmer" aria-label="ourism">
                                        {Array.from('ourism').map((char, index) => (
                                            <motion.span key={`ourism-${index}`} variants={titleLetter}>
                                                {char}
                                            </motion.span>
                                        ))}
                                    </span>
                                </motion.h1>

                                <div className="mb-14 space-y-2.5 px-2">
                                    <h2 className="text-4xl md:text-6xl font-serif italic text-[#00703C] serif-glow">
                                        <SpecialText
                                            className="justify-center text-[0.95em] tracking-[0.02em] text-[#00703C]"
                                            delay={0.2}
                                            inView
                                        >
                                            Plan smarter.
                                        </SpecialText>
                                    </h2>
                                    <h2 className="text-4xl md:text-6xl font-serif italic text-[#B3A369] serif-glow">
                                        <SpecialText
                                            className="justify-center text-[0.95em] tracking-[0.02em] text-[#B3A369]"
                                            delay={0.6}
                                            inView
                                        >
                                            Explore better.
                                        </SpecialText>
                                    </h2>
                                </div>

                                <div className="flex flex-col items-center gap-8">
                                    <GlowButton onClick={() => navigate('/login')}>
                                        Get Started
                                    </GlowButton>

                                    <button 
                                        onClick={openPlanner} 
                                        className="group flex flex-col items-center gap-2 transition-all"
                                    >
                                        <span className="text-lg md:text-xl uppercase tracking-[0.3em] text-white/40 group-hover:text-white transition-colors duration-300 font-medium italic font-serif">
                                            Or try the planner first
                                        </span>
                                        <div className="h-[1px] w-12 bg-[#B3A369]/30 group-hover:w-full group-hover:bg-[#B3A369] transition-all duration-500"></div>
                                    </button>

                                    <motion.div
                                        initial={reduceMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: -2 }}
                                        animate={reduceMotion ? { opacity: 1, y: 0 } : { opacity: [0.45, 1, 0.45], y: [0, 8, 0] }}
                                        transition={reduceMotion ? { duration: 0.15 } : { duration: 2.3, repeat: Infinity, ease: 'easeInOut' }}
                                        className="group mt-2 inline-flex items-center rounded-full px-4 py-2 text-[10px] font-black uppercase tracking-[0.28em] text-white/50"
                                        aria-hidden
                                    >
                                        <span className="inline-flex h-5 w-3" />
                                    </motion.div>
                                </div>
                            </motion.div>
                        </Reveal>
                    </div>
                ) : (
                    <div className="mx-auto flex h-full min-h-[calc(100vh-2in)] w-full max-w-7xl flex-col overflow-hidden">
                        <div className="flex-1 overflow-hidden pt-3">
                            <AnimatePresence mode="wait">
                                <motion.div
                                    key={`planner-step-${step}`}
                                    initial={reduceMotion ? { opacity: 0, y: 0 } : { opacity: 0, y: 16 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={reduceMotion ? { opacity: 0, y: 0 } : { opacity: 0, y: 12 }}
                                    transition={{ duration: reduceMotion ? 0.16 : 0.34, ease: 'easeOut' }}
                                    className="min-w-0"
                                >
                                    {renderPlannerStep()}
                                </motion.div>
                            </AnimatePresence>
                        </div>

                        <div className="flex justify-center gap-3 pb-6 pt-4">
                            {plannerSteps.map((plannerStep) => (
                                <span
                                    key={plannerStep}
                                    className={`h-2.5 w-2.5 rounded-full transition-all duration-300 ${
                                        currentPlannerStep >= plannerStep ? 'bg-emerald shadow-[0_0_14px_rgba(16,185,129,0.6)]' : 'bg-white/25'
                                    }`}
                                />
                            ))}
                        </div>
                    </div>
                )}

                {step === 0 && (
                    <div ref={storySectionRef} className="relative mx-auto mt-10 w-full max-w-7xl pb-10">
                        <div className="pointer-events-none absolute inset-0 -z-10 opacity-35">
                            <div className="grid-bg absolute inset-0 rounded-[2rem]" />
                        </div>

                        <div className="space-y-24">
                            <section>
                                <div className="glass-card flex flex-col items-start justify-between gap-8 rounded-[2.2rem] p-10 md:flex-row md:items-center md:p-12">
                                    <div className="max-w-3xl">
                                        <p className="mb-4 text-[11px] font-black uppercase tracking-[0.36em] text-gold/80">READY WHEN YOU ARE</p>
                                        <h2 className="text-4xl font-serif italic leading-tight text-[#F9F8F3] md:text-5xl">
                                            Build your personalized Charlotte day in under a minute.
                                        </h2>
                                    </div>
                                    <GlowButton onClick={openPlanner} className="whitespace-nowrap px-10 py-4">
                                        OPEN PLANNER
                                    </GlowButton>
                                </div>
                            </section>

                            <section className="space-y-10">
                                <SectionHeader eyebrow="WHY TRAVELERS LOVE IT" title="Made to feel effortless" />
                                <div className="grid gap-7 md:grid-cols-3">
                                    <TestimonialCard
                                        quote="It felt like having a private concierge in my pocket—clean, fast, and beautifully designed."
                                        author="ALEX M. · WEEKEND TRAVELER"
                                    />
                                    <TestimonialCard
                                        quote="The itinerary flow was smooth and surprisingly thoughtful. We spent more time enjoying and less time deciding."
                                        author="PRIYA K. · CHARLOTTE VISITOR"
                                    />
                                    <TestimonialCard
                                        quote="Modern, friendly, and premium without feeling overwhelming. Exactly what trip planning should feel like."
                                        author="JORDAN T. · FIRST-TIME GUEST"
                                    />
                                </div>
                            </section>

                            <section className="space-y-10">
                                <SectionHeader eyebrow="HOW IT WORKS" title="A simple flow with a premium feel" />
                                <div className="grid gap-7 md:grid-cols-3">
                                    <FeatureStepCard
                                        step="01"
                                        title="Share your style"
                                        body="Choose the atmosphere you’re in the mood for, from social and lively to relaxed and elegant."
                                    />
                                    <FeatureStepCard
                                        step="02"
                                        title="Set your comfort level"
                                        body="Pick your date, preferred pace, and budget range so every recommendation feels right for you."
                                    />
                                    <FeatureStepCard
                                        step="03"
                                        title="Enjoy your curated day"
                                        body="Get a live itinerary with smooth transitions, optional discoveries, and a beautiful map-driven experience."
                                    />
                                </div>
                            </section>

                            <section className="space-y-10">
                                <SectionHeader eyebrow="FAQ" title="Quick answers" />
                                <div className="space-y-6">
                                    <FaqCard
                                        question="How long does planning take?"
                                        answer="Usually under a minute. Pick your preferences and we generate a complete day flow instantly."
                                    />
                                    <FaqCard
                                        question="Can I adjust the plan after it generates?"
                                        answer="Yes. You can swap between active schedule items and discovery suggestions at any time."
                                    />
                                    <FaqCard
                                        question="Is this only for tourists?"
                                        answer="Not at all. Locals use it to find fresh ideas for weekends, date nights, and group plans too."
                                    />
                                </div>
                            </section>

                            <section className="space-y-10">
                                <SectionHeader eyebrow="ABOUT CLTOURISM" title="A friendly high-end planning experience" />
                                <p className="max-w-3xl text-lg leading-relaxed text-white/75">
                                    Built for travelers who want premium recommendations without the planning stress. It’s modern, warm, and designed to feel as good as the day itself.
                                </p>

                                <div className="grid gap-7 md:grid-cols-3">
                                    <VisualStoryCard
                                        image="/img/uptown1.jpg"
                                        title="Curated City Moments"
                                        description="From skyline brunches to evening music lounges, your day feels effortless and elevated."
                                    />
                                    <VisualStoryCard
                                        image="/img/cltskyline1.jpg"
                                        title="Premium Comfort Routing"
                                        description="Smart timing and smooth transitions so you spend less time planning and more time enjoying."
                                    />
                                    <VisualStoryCard
                                        image="/img/cltconcert.avif"
                                        title="Live Local Energy"
                                        description="Discover what’s happening right now in Charlotte with a polished, personalized itinerary."
                                    />
                                </div>
                            </section>
                        </div>
                    </div>
                )}
            </PageLayout>
        </div>
    );
};

export default Home;
